import '../lib/export_name.dart';
import '../lib/report_bundle.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  check(
    portableSegment('LPT1.audit') == '_LPT1.audit',
    'a device basename remains reserved when it has an extension',
  );

  final bundle = ReportBundle();
  check(
    bundle.allocateEntry('AUX.', 'daily.') == '_AUX/daily.txt',
    'normalizes both path segments before allocation',
  );
  check(
    bundle.allocateEntry('_aux', 'DAILY') == '_aux/DAILY (2).txt',
    'collisions introduced by normalization and casing are suffixed',
  );

  print('final tests passed');
}
